116→
117→// Orders / Transactions
118→export interface Order {
119→  id: string;
120→  productId: string;
121→  productTitle: string;
122→  customerName: string;
123→  customerEmail: string;
124→  amount: number;
125→  currency: string;
126→  status: 'completed' | 'refunded' | 'pending' | 'failed';
127→  paymentMethod: 'stripe' | 'paypal';
