103→// Page aliases for active item highlighting
104→const PAGE_ALIASES: Record<string, string> = {
105→  'analyze': 'new-analysis',
106→  'audit-aeo': 'results',
107→  'alerts': 'alerts-aeo',
108→  'answer-first-audit': 'answer-first',
