115→  'directory-entity': 'directory',
116→  'rescan': 'projects',
117→};
118→
119→export { NAV_GROUPS, PAGE_ALIASES };
120→
121→function resolveActivePage(pageId: string): string {
122→  return PAGE_ALIASES[pageId] || pageId;
123→}
124→
125→// Derive section from page
126→export function getSectionFromPage(pageId: string): string {
127→  const resolved = resolveActivePage(pageId);
128→  for (const group of NAV_GROUPS) {
129→    if (group.items.some(item => item.id === resolved)) {
130→      return group.id;
131→    }
132→  }
133→  return 'overview';
134→}
