166→        key={item.id}
167→        onClick={() => { onPageChange(item.id); onClose?.(); }}
168→        className={`group flex items-center gap-2.5 w-full px-3 py-[7px] rounded-lg text-[13px] leading-none cursor-pointer transition-all duration-150 relative ${
