import React, { useState, useRef, useEffect } from 'react';
import { DollarSign, ChevronDown, LogOut, Settings, User as UserIcon } from 'lucide-react';
import ThemeToggle from '../ui/ThemeToggle';

interface HeaderUser {
  name: string;
  avatar?: string;
}

interface HeaderProps {
  user: HeaderUser | null;
  onLogoClick?: () => void;
  onNavigate?: (page: string) => void;
}

export default function Header({ user, onLogoClick, onNavigate }: HeaderProps) {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown on outside click
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setDropdownOpen(false);
      }
    }
    if (dropdownOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [dropdownOpen]);

  return (
    <header className="h-12 shrink-0 bg-[var(--bg-surface)] border-b border-[var(--border-default)] flex items-center px-4 gap-4 z-30">
      {/* ═══ Left: Logo ═══ */}
      <div
        className="flex items-center cursor-pointer shrink-0 mr-2"
        onClick={onLogoClick}
      >
        <span className="text-[var(--text-primary)] font-bold text-[15px] tracking-tight">
          Stan
        </span>
        <span className="text-[var(--accent)] font-normal text-[13px]">.io</span>
      </div>

      {/* ═══ Center: empty (minimal) ═══ */}
      <div className="flex-1" />

      {/* ═══ Right: Revenue + Theme + Avatar ═══ */}
      <div className="flex items-center gap-3 shrink-0">
        {/* Revenue indicator */}
        {user && (
          <div className="flex items-center gap-1.5 text-[13px] text-[var(--text-secondary)]">
            <DollarSign className="w-3.5 h-3.5 text-[var(--success)]" />
            <span className="font-medium text-[var(--text-primary)]">0.00</span>
          </div>
        )}

        <ThemeToggle />

        {/* Avatar with dropdown */}
        {user && (
          <div className="relative" ref={dropdownRef}>
            <button
              onClick={() => setDropdownOpen(!dropdownOpen)}
              className="flex items-center gap-1.5 cursor-pointer group"
            >
              {user.avatar ? (
                <img
                  src={user.avatar}
                  alt={user.name}
                  className="w-7 h-7 rounded-full object-cover ring-1 ring-[var(--border-default)]"
                />
              ) : (
                <div className="w-7 h-7 rounded-full bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-[11px] text-white font-semibold ring-1 ring-[var(--border-default)]">
                  {user.name?.charAt(0)?.toUpperCase() || 'U'}
                </div>
              )}
              <ChevronDown
                size={12}
                className={`text-[var(--text-tertiary)] group-hover:text-[var(--text-secondary)] transition-transform duration-200 ${
                  dropdownOpen ? 'rotate-180' : ''
                }`}
              />
            </button>

            {/* Dropdown menu */}
            {dropdownOpen && (
              <div className="absolute right-0 top-full mt-1.5 w-48 rounded-lg bg-[var(--bg-surface)] border border-[var(--border-default)] shadow-lg py-1 z-50">
                {/* User info */}
                <div className="px-3 py-2 border-b border-[var(--border-subtle)]">
                  <p className="text-[13px] font-medium text-[var(--text-primary)] truncate">
                    {user.name}
                  </p>
                </div>

                {/* Menu items */}
                <button
                  onClick={() => {
                    onNavigate?.('account');
                    setDropdownOpen(false);
                  }}
                  className="flex items-center gap-2 w-full px-3 py-2 text-[13px] text-[var(--text-secondary)] hover:text-[var(--text-primary)] hover:bg-[var(--glass-active)] transition-colors"
                >
                  <UserIcon size={14} />
                  <span>My Account</span>
                </button>
                <button
                  onClick={() => {
                    onNavigate?.('store-settings');
                    setDropdownOpen(false);
                  }}
                  className="flex items-center gap-2 w-full px-3 py-2 text-[13px] text-[var(--text-secondary)] hover:text-[var(--text-primary)] hover:bg-[var(--glass-active)] transition-colors"
                >
                  <Settings size={14} />
                  <span>Settings</span>
                </button>

                <div className="border-t border-[var(--border-subtle)] mt-1 pt-1">
                  <button
                    onClick={() => setDropdownOpen(false)}
                    className="flex items-center gap-2 w-full px-3 py-2 text-[13px] text-[var(--error)] hover:bg-[var(--error-subtle)] transition-colors"
                  >
                    <LogOut size={14} />
                    <span>Log Out</span>
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </header>
  );
}

import React, { useState } from 'react';
import {
  LayoutDashboard, Store,
  Package, FileDown, GraduationCap, CalendarClock, Crown,
  ShoppingCart, Users, UserPlus,
  Mail, Send, Ticket,
  BarChart3, Globe,
  Settings, Link2, CreditCard, UserCog,
  Menu, X,
} from 'lucide-react';
import CollapsibleSection from '../ui/CollapsibleSection';

// ═══════════════════════════════════════════════════════════
// NAVIGATION STRUCTURE
// ═══════════════════════════════════════════════════════════

interface NavItem {
  id: string;
  label: string;
  icon: React.ElementType;
  badge?: string;
}

interface NavGroup {
  id: string;
  title: string;
  items: NavItem[];
}

const NAV_GROUPS: NavGroup[] = [
  {
    id: 'home',
    title: 'Home',
    items: [
      { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
      { id: 'my-store', label: 'My Store', icon: Store },
    ],
  },
  {
    id: 'products',
    title: 'Products',
    items: [
      { id: 'all-products', label: 'All Products', icon: Package },
      { id: 'digital-products', label: 'Digital Products', icon: FileDown },
      { id: 'courses', label: 'Courses', icon: GraduationCap },
      { id: 'bookings', label: 'Bookings', icon: CalendarClock },
      { id: 'memberships', label: 'Memberships', icon: Crown },
    ],
  },
  {
    id: 'customers',
    title: 'Customers',
    items: [
      { id: 'orders', label: 'Orders', icon: ShoppingCart },
      { id: 'subscribers', label: 'Subscribers', icon: Users },
      { id: 'affiliates', label: 'Affiliates', icon: UserPlus },
    ],
  },
  {
    id: 'marketing',
    title: 'Marketing',
    items: [
      { id: 'email-flows', label: 'Email Flows', icon: Mail },
      { id: 'broadcasts', label: 'Broadcasts', icon: Send },
      { id: 'discount-codes', label: 'Discount Codes', icon: Ticket },
    ],
  },
  {
    id: 'analytics',
    title: 'Analytics',
    items: [
      { id: 'analytics-overview', label: 'Overview', icon: BarChart3 },
      { id: 'traffic-sources', label: 'Traffic Sources', icon: Globe },
    ],
  },
  {
    id: 'settings',
    title: 'Settings',
    items: [
      { id: 'store-settings', label: 'Store Settings', icon: Settings },
      { id: 'integrations', label: 'Integrations', icon: Link2 },
      { id: 'payment-setup', label: 'Payment Setup', icon: CreditCard },
      { id: 'account', label: 'Account', icon: UserCog },
    ],
  },
];

// Page aliases for active item highlighting
const PAGE_ALIASES: Record<string, string> = {
  'products': 'all-products',
  'settings': 'store-settings',
};

export { NAV_GROUPS, PAGE_ALIASES };

function resolveActivePage(pageId: string): string {
  return PAGE_ALIASES[pageId] || pageId;
}

// Derive section from page
export function getSectionFromPage(pageId: string): string {
  const resolved = resolveActivePage(pageId);
  for (const group of NAV_GROUPS) {
    if (group.items.some(item => item.id === resolved)) {
      return group.id;
    }
  }
  return 'home';
}

// ═══════════════════════════════════════════════════════════
// COMPONENT
// ═══════════════════════════════════════════════════════════

interface SidebarUser {
  name: string;
  avatar?: string;
}

interface SidebarProps {
  activePage: string;
  onPageChange: (page: string) => void;
  user?: SidebarUser | null;
  plan?: 'creator' | 'creator-pro';
}

export default function Sidebar({
  activePage,
  onPageChange,
  user,
  plan = 'creator',
}: SidebarProps) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const resolved = resolveActivePage(activePage);

  const renderNavItem = (item: NavItem, onClose?: () => void) => {
    const Icon = item.icon;
    const isActive = resolved === item.id;

    return (
      <button
        key={item.id}
        onClick={() => {
          onPageChange(item.id);
          onClose?.();
        }}
        className={`group flex items-center gap-2.5 w-full px-3 py-[7px] rounded-lg text-[13px] leading-none cursor-pointer transition-all duration-150 relative ${
          isActive
            ? 'text-[var(--text-primary)] bg-[var(--accent-subtle)] font-medium'
            : 'text-[var(--text-secondary)] hover:text-[var(--text-primary)] hover:bg-[var(--glass-active)]'
        }`}
      >
        {/* Active accent bar */}
        {isActive && (
          <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[3px] h-4 bg-[var(--accent)] rounded-r-full" />
        )}
        <Icon
          className={`w-4 h-4 flex-shrink-0 ${
            isActive
              ? 'text-[var(--accent)]'
              : 'text-[var(--text-tertiary)] group-hover:text-[var(--text-secondary)]'
          }`}
        />
        <span className="truncate">{item.label}</span>
        {item.badge && (
          <span className="ml-auto text-[10px] font-semibold min-w-[18px] h-[18px] rounded-full flex items-center justify-center px-1 bg-[var(--error-subtle)] text-[var(--error)]">
            {item.badge}
          </span>
        )}
      </button>
    );
  };

  const renderSidebarContent = (onClose?: () => void) => (
    <>
      {/* Nav groups */}
      <nav className="flex-1 overflow-y-auto py-2 px-2">
        {NAV_GROUPS.map(group => (
          <CollapsibleSection key={group.id} title={group.title}>
            {group.items.map(item => renderNavItem(item, onClose))}
          </CollapsibleSection>
        ))}
      </nav>

      {/* Footer: user avatar + plan badge */}
      <div className="border-t border-[var(--border-default)] p-3 shrink-0 space-y-2">
        {/* Plan badge */}
        <div className="px-1">
          <div className="flex items-center justify-between">
            <span className="text-[12px] text-[var(--text-secondary)]">Plan</span>
            <span
              className={`text-[11px] font-semibold uppercase px-2 py-0.5 rounded-full ${
                plan === 'creator-pro'
                  ? 'bg-[var(--accent-subtle)] text-[var(--accent-text)]'
                  : 'bg-[var(--glass-surface)] text-[var(--text-secondary)]'
              }`}
            >
              {plan === 'creator-pro' ? 'Creator Pro' : 'Creator'}
            </span>
          </div>
        </div>

        {/* User info */}
        {user && (
          <div className="flex items-center gap-2.5 px-2 py-1.5">
            {user.avatar ? (
              <img
                src={user.avatar}
                alt={user.name}
                className="w-7 h-7 rounded-full object-cover ring-1 ring-[var(--border-default)]"
              />
            ) : (
              <div className="w-7 h-7 rounded-full bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-[11px] text-white font-semibold ring-1 ring-[var(--border-default)]">
                {user.name?.charAt(0)?.toUpperCase() || 'U'}
              </div>
            )}
            <span className="text-[13px] text-[var(--text-primary)] font-medium truncate">
              {user.name}
            </span>
          </div>
        )}
      </div>
    </>
  );

  return (
    <>
      {/* ═══ Desktop sidebar ═══ */}
      <aside className="hidden md:flex flex-col shrink-0 w-56 bg-[var(--bg-sidebar)] border-r border-[var(--border-default)] overflow-hidden">
        {renderSidebarContent()}
      </aside>

      {/* ═══ Mobile hamburger button ═══ */}
      <button
        onClick={() => setMobileOpen(!mobileOpen)}
        className="md:hidden fixed top-2 left-2 z-[60] p-2 rounded-lg bg-[var(--bg-elevated)] text-[var(--text-secondary)] hover:text-[var(--text-primary)] transition-colors"
        aria-label="Toggle navigation"
      >
        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
      </button>

      {/* ═══ Mobile overlay ═══ */}
      {mobileOpen && (
        <>
          {/* Backdrop */}
          <div
            className="md:hidden fixed inset-0 z-[55] bg-black/40 backdrop-blur-sm"
            onClick={() => setMobileOpen(false)}
          />

          {/* Drawer */}
          <aside className="md:hidden flex flex-col fixed top-0 left-0 bottom-0 w-72 z-[56] bg-[var(--bg-sidebar)] border-r border-[var(--border-default)]">
            {/* Mobile logo header */}
            <div className="px-5 h-12 flex items-center border-b border-[var(--border-default)] shrink-0">
              <span className="text-[var(--text-primary)] font-bold text-[15px] tracking-tight">
                Stan
              </span>
